// ServerInterface represents all server handlers.
type ServerInterface interface {

	// (POST /v1/devtools/publish-module)
	PublishModule(w http.ResponseWriter, r *http.Request)

	// (POST /v1/devtools/update-module-version)
	UpdateModuleVersion(w http.ResponseWriter, r *http.Request)

	// (GET /v1/health)
	HealthCheck(w http.ResponseWriter, r *http.Request)

	// (POST /v1/mcp)
	HandleMcp(w http.ResponseWriter, r *http.Request)
	// Search the public module catalog
	// (GET /v1/modules/search)
	SearchPublicModules(w http.ResponseWriter, r *http.Request, params SearchPublicModulesParams)
	// Get full details of a public module
	// (GET /v1/modules/{name})
	GetPublicModule(w http.ResponseWriter, r *http.Request, name string)
	// Export solution using one-time token
	// (GET /v1/solutions/export)
	ExportSolution(w http.ResponseWriter, r *http.Request, params ExportSolutionParams)
	// Search public solutions catalog
	// (GET /v1/solutions/search)
	SearchPublicSolutions(w http.ResponseWriter, r *http.Request, params SearchPublicSolutionsParams)
	// Get full details of a public solution
	// (GET /v1/solutions/{uuid})
	GetPublicSolution(w http.ResponseWriter, r *http.Request, uuid string)
}

